// // This module is designed to decrement a 4-bit value on each rising edge of the clock and reset to 16 when the reset signal is asserted.
module top_module(
    input clk,
    input rst,
    output reg [3:0] out
);always @(posedge clk) begin
    if (rst) begin
        out <= 4'b0000;
    end else begin
        out <= out + 1;
    end
end

endmodule
